```php
if ($strategy === 'callable') {
    $hookResult = $this->manager->fireNoRoleMatch($identity, $provider);
    if ($hookResult instanceof RedirectResponse) {
        return $hookResult;
    }
}

if ($strategy === 'deny') {
    return redirect()->route('martis.login')->withErrors(['sso' => __('martis::messages.sso_no_role_match')]);
}
```

